-- ════════════════════════════════════════════════════════════════════════════
-- 시드 콘텐츠: Blender 오픈무비 9편 (전부 CC-BY) — 어드민 업로드(Bunny Stream)
-- 적용 일자: 2026-06-06
-- · video_url/thumbnail = Bunny CDN, creator_id = 어드민, license = cc-by
-- · show_on_ott/cinema 는 트리거(classify_video_placement)가 길이로 자동 설정
--   (10분=600초 이상 → OTT, 1분 이상 → 시네마)
-- ════════════════════════════════════════════════════════════════════════════
ON CONFLICT (id) DO UPDATE SET title=EXCLUDED.title, video_url=EXCLUDED.video_url, thumbnail=EXCLUDED.thumbnail, duration=EXCLUDED.duration, duration_seconds=EXCLUDED.duration_seconds, category=EXCLUDED.category, genre=EXCLUDED.genre, status=EXCLUDED.status, license_type=EXCLUDED.license_type, license_source_url=EXCLUDED.license_source_url, attribution=EXCLUDED.attribution, original_creator=EXCLUDED.original_creator;
